"use client"

import Link from "next/link"
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from "@/components/ui/card"
import { MessageSquare, Users, Settings } from "lucide-react"
import { useUser } from "@/hooks/useUser"
import { useConversations } from "@/hooks/useConversations"
import { useTeam } from "@/hooks/useUser"

function formatRelativeTime(dateString: string | null | undefined): string {
  if (!dateString) {
    console.warn('formatRelativeTime: No date string provided')
    return "Unknown"
  }
  
  try {
    const date = new Date(dateString)
    const now = new Date()
    
    // Check if date is valid
    if (isNaN(date.getTime())) {
      console.warn('Invalid date:', dateString, 'Parsed as:', date)
      return "Unknown"
    }
    
    const diffMs = now.getTime() - date.getTime()
    
    // Handle future dates or invalid calculations
    if (isNaN(diffMs) || diffMs < 0) {
      return "just now"
    }
    
    const diffSec = Math.floor(diffMs / 1000)
    const diffMin = Math.floor(diffMs / 60000)
    const diffHr = Math.floor(diffMs / 3600000)
    const diffDay = Math.floor(diffMs / 86400000)

    if (diffSec < 60) return "just now"
    if (diffMin < 60) return `${diffMin}m ago`
    if (diffHr < 24) return `${diffHr}h ago`
    if (diffDay === 1) return "Yesterday"
    if (diffDay < 7) return `${diffDay}d ago`
    if (diffDay < 30) {
      const weeks = Math.floor(diffDay / 7)
      return weeks === 1 ? "1 week ago" : `${weeks} weeks ago`
    }
    if (diffDay < 365) {
      const months = Math.floor(diffDay / 30)
      return months === 1 ? "1 month ago" : `${months} months ago`
    }
    const years = Math.floor(diffDay / 365)
    return years === 1 ? "1 year ago" : `${years} years ago`
  } catch (error) {
    console.error('Error formatting date:', dateString, error)
    return "Unknown"
  }
}

export default function DashboardPage() {
  const { data: user } = useUser()
  const { data: conversations = [], isLoading: conversationsLoading } = useConversations()
  const { data: team = [], isLoading: teamLoading } = useTeam()
  const firstName = user?.fullName?.split(' ')[0] || ''

  const stats = [
    {
      title: "Conversations",
      value: conversationsLoading ? "..." : conversations.length.toString(),
      description: "Total AI chats",
      icon: MessageSquare,
      href: "/chat",
    },
    {
      title: "Team Members",
      value: teamLoading ? "..." : team.length.toString(),
      description: "Active collaborators",
      icon: Users,
      href: "/settings?tab=team",
    },
  ]

  // Get latest 3 conversations sorted by updatedAt
  const recentConversations = [...conversations]
    .filter(c => c.updatedAt) // Filter out conversations without updatedAt
    .sort((a, b) => {
      const aTime = new Date(a.updatedAt).getTime()
      const bTime = new Date(b.updatedAt).getTime()
      return bTime - aTime
    })
    .slice(0, 3)

  return (
    <div className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold tracking-tight text-foreground text-balance">
          {firstName ? `Welcome back, ${firstName}` : 'Welcome back'}
        </h1>
        <p className="text-sm text-muted-foreground">
          {"Here's an overview of your workspace"}
        </p>
      </div>

      <div className="grid gap-4 sm:grid-cols-2">
        {stats.map((stat) => (
          <Link key={stat.title} href={stat.href}>
            <Card className="transition-colors hover:bg-accent/50">
              <CardHeader className="flex flex-row items-center justify-between pb-2">
                <CardTitle className="text-sm font-medium text-muted-foreground">
                  {stat.title}
                </CardTitle>
                <stat.icon className="size-4 text-muted-foreground" />
              </CardHeader>
              <CardContent>
                <div className="text-2xl font-bold text-foreground">
                  {stat.value}
                </div>
                <CardDescription className="text-xs">
                  {stat.description}
                </CardDescription>
              </CardContent>
            </Card>
          </Link>
        ))}
      </div>

      <div className="grid gap-4 lg:grid-cols-2">
        <Card>
          <CardHeader>
            <CardTitle className="text-base">Recent Activity</CardTitle>
            <CardDescription>Your latest conversations</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="flex flex-col gap-4">
              {conversationsLoading ? (
                <div className="text-sm text-muted-foreground">Loading...</div>
              ) : recentConversations.length === 0 ? (
                <div className="text-sm text-muted-foreground">No conversations yet</div>
              ) : (
                recentConversations.map((conversation) => (
                  <Link
                    key={conversation.id}
                    href={`/chat?conversation=${conversation.id}`}
                    className="flex items-start gap-3 rounded-lg p-2 transition-colors hover:bg-muted/50"
                  >
                    <div className="mt-1 size-2 shrink-0 rounded-full bg-primary" />
                    <div className="flex flex-col gap-0.5 flex-1 min-w-0">
                      <span className="text-sm font-medium text-foreground truncate">
                        {conversation.title}
                      </span>
                      <span className="text-xs text-muted-foreground">
                        {conversation.messageCount} {conversation.messageCount === 1 ? 'message' : 'messages'}
                      </span>
                    </div>
                    <span className="ml-auto shrink-0 text-xs text-muted-foreground">
                      {formatRelativeTime(conversation.updatedAt)}
                    </span>
                  </Link>
                ))
              )}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle className="text-base">Quick Actions</CardTitle>
            <CardDescription>Jump to common tasks</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="flex flex-col gap-2">
              {[
                {
                  label: "Start a new chat",
                  description: "Ask AI anything",
                  href: "/chat",
                  icon: MessageSquare,
                },
                {
                  label: "Update your profile",
                  description: "Edit name and preferences",
                  href: "/settings",
                  icon: Settings,
                },
                {
                  label: "Manage your team",
                  description: "Invite members and set roles",
                  href: "/settings?tab=team",
                  icon: Users,
                },
              ].map((item) => (
                <Link
                  key={item.label}
                  href={item.href}
                  className="flex items-center gap-3 rounded-lg p-3 transition-colors hover:bg-muted/50"
                >
                  <div className="flex size-9 shrink-0 items-center justify-center rounded-lg bg-muted">
                    <item.icon className="size-4 text-muted-foreground" />
                  </div>
                  <div className="flex flex-col gap-0.5">
                    <span className="text-sm font-medium text-foreground">
                      {item.label}
                    </span>
                    <span className="text-xs text-muted-foreground">
                      {item.description}
                    </span>
                  </div>
                </Link>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}
